package test.rice.concisegen;

import main.rice.concisegen.ConciseSetGenerator;
import main.rice.obj.APyObj;
import main.rice.obj.PyIntObj;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

class AgentConciseSetGeneratorTest {

    private TestCase createTestCase(int... args) {
        List<APyObj> objArgs = new ArrayList<>();
        for (int arg : args) {
            objArgs.add(new PyIntObj(arg));
        }
        return new TestCase(objArgs);
    }

    // ==================== Basic coverage tests ====================

    @Test
    void testEmptyWrongSet() {
        List<TestCase> allCases = Arrays.asList(createTestCase(1));
        List<Set<Integer>> caseToFiles = Arrays.asList(new HashSet<>());
        Set<Integer> wrongSet = new HashSet<>();

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertTrue(cover.isEmpty());
    }

    @Test
    void testSingleTestCoversAll() {
        List<TestCase> allCases = Arrays.asList(createTestCase(1));
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1, 2))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }

    @Test
    void testEachTestCoversOneFile() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1)),
            new HashSet<>(Arrays.asList(2))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(3, cover.size());
    }

    @Test
    void testGreedySelectsBest() {
        // Test 0 covers {0, 1, 2}, Test 1 covers {0}, Test 2 covers {1}
        // Greedy should pick Test 0 first and that covers everything
        List<TestCase> allCases = Arrays.asList(
            createTestCase(10),
            createTestCase(20),
            createTestCase(30)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1, 2)),
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(10)));
    }

    @Test
    void testTwoTestsNeeded() {
        // Test 0 covers {0, 1}, Test 1 covers {2, 3}, Test 2 covers {0, 3}
        // Need at least 2; greedy picks test 0 or 1 first (both cover 2),
        // then needs one more
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(2, 3)),
            new HashSet<>(Arrays.asList(0, 3))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2, 3));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(2, cover.size());
        // The cover should catch all wrong files
        Set<Integer> covered = new HashSet<>();
        for (TestCase tc : cover) {
            int idx = allCases.indexOf(tc);
            covered.addAll(caseToFiles.get(idx));
        }
        assertTrue(covered.containsAll(wrongSet));
    }

    @Test
    void testDoesNotMutateWrongSet() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));
        Set<Integer> originalWrongSet = new HashSet<>(wrongSet);

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        ConciseSetGenerator.setCover(results);

        assertEquals(originalWrongSet, wrongSet);
    }

    @Test
    void testResultCoversAllWrongFiles() {
        // More complex scenario
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3),
            createTestCase(4),
            createTestCase(5)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(1, 2)),
            new HashSet<>(Arrays.asList(2, 3)),
            new HashSet<>(Arrays.asList(3, 4)),
            new HashSet<>(Arrays.asList(0, 4))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2, 3, 4));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);

        // Verify all wrong files are covered
        Set<Integer> covered = new HashSet<>();
        for (TestCase tc : cover) {
            int idx = allCases.indexOf(tc);
            covered.addAll(caseToFiles.get(idx));
        }
        assertTrue(covered.containsAll(wrongSet));
    }

    @Test
    void testSingleWrongFile() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>()
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }

    @Test
    void testOverlappingCoverage() {
        // All 3 tests cover file 0; test 0 also covers file 1
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(0))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }
}

package test.rice.node;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
import main.rice.node.PyIntNode;
import main.rice.node.PyFloatNode;
import main.rice.obj.PyBoolObj;
import main.rice.obj.PyIntObj;
import main.rice.obj.PyFloatObj;
import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

class AgentNodeTest {

    // ==================== PyBoolNode Tests ====================

    @Test
    void testBoolGetLeftChildNull() {
        PyBoolNode node = new PyBoolNode();
        assertNull(node.getLeftChild());
    }

    @Test
    void testBoolGetRightChildNull() {
        PyBoolNode node = new PyBoolNode();
        assertNull(node.getRightChild());
    }

    @Test
    void testBoolGenExValsBoth() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(0, 1));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(2, vals.size());
        assertTrue(vals.contains(new PyBoolObj(false)));
        assertTrue(vals.contains(new PyBoolObj(true)));
    }

    @Test
    void testBoolGenExValsFalseOnly() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(0));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyBoolObj(false)));
    }

    @Test
    void testBoolGenExValsTrueOnly() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(1));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyBoolObj(true)));
    }

    @Test
    void testBoolGenRandValInDomain() {
        PyBoolNode node = new PyBoolNode();
        node.setRanDomain(Arrays.asList(0, 1));
        for (int i = 0; i < 50; i++) {
            PyBoolObj val = node.genRandVal();
            assertTrue(val.getValue() == true || val.getValue() == false);
        }
    }

    @Test
    void testBoolGenRandValSingleDomain() {
        PyBoolNode node = new PyBoolNode();
        node.setRanDomain(Arrays.asList(1));
        for (int i = 0; i < 20; i++) {
            PyBoolObj val = node.genRandVal();
            assertTrue(val.getValue());
        }
    }

    // ==================== PyIntNode Tests ====================

    @Test
    void testIntGetLeftChildNull() {
        PyIntNode node = new PyIntNode();
        assertNull(node.getLeftChild());
    }

    @Test
    void testIntGetRightChildNull() {
        PyIntNode node = new PyIntNode();
        assertNull(node.getRightChild());
    }

    @Test
    void testIntGenExVals() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(-3, 0, 5));
        Set<PyIntObj> vals = node.genExVals();
        assertEquals(3, vals.size());
        assertTrue(vals.contains(new PyIntObj(-3)));
        assertTrue(vals.contains(new PyIntObj(0)));
        assertTrue(vals.contains(new PyIntObj(5)));
    }

    @Test
    void testIntGenExValsSingle() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(42));
        Set<PyIntObj> vals = node.genExVals();
        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyIntObj(42)));
    }

    @Test
    void testIntGenExValsDuplicates() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(1, 1, 2));
        Set<PyIntObj> vals = node.genExVals();
        assertEquals(2, vals.size());
        assertTrue(vals.contains(new PyIntObj(1)));
        assertTrue(vals.contains(new PyIntObj(2)));
    }

    @Test
    void testIntGenRandValInDomain() {
        PyIntNode node = new PyIntNode();
        List<Integer> domain = Arrays.asList(-10, -5, 0, 5, 10);
        node.setRanDomain(domain);
        Set<Integer> domainSet = new HashSet<>(domain);
        for (int i = 0; i < 100; i++) {
            PyIntObj val = node.genRandVal();
            assertTrue(domainSet.contains(val.getValue()));
        }
    }

    // ==================== PyFloatNode Tests ====================

    @Test
    void testFloatGetLeftChildNull() {
        PyFloatNode node = new PyFloatNode();
        assertNull(node.getLeftChild());
    }

    @Test
    void testFloatGetRightChildNull() {
        PyFloatNode node = new PyFloatNode();
        assertNull(node.getRightChild());
    }

    @Test
    void testFloatGenExVals() {
        PyFloatNode node = new PyFloatNode();
        node.setExDomain(Arrays.asList(-1.5, 0.0, 3.14));
        Set<PyFloatObj> vals = node.genExVals();
        assertEquals(3, vals.size());
        assertTrue(vals.contains(new PyFloatObj(-1.5)));
        assertTrue(vals.contains(new PyFloatObj(0.0)));
        assertTrue(vals.contains(new PyFloatObj(3.14)));
    }

    @Test
    void testFloatGenRandValInDomain() {
        PyFloatNode node = new PyFloatNode();
        List<Double> domain = Arrays.asList(-1.0, 0.0, 1.0);
        node.setRanDomain(domain);
        Set<Double> domainSet = new HashSet<>(domain);
        for (int i = 0; i < 100; i++) {
            PyFloatObj val = node.genRandVal();
            assertTrue(domainSet.contains(val.getValue()));
        }
    }

    // ==================== Domain setter/getter edge cases ====================

    @Test
    void testBoolExDomainEmpty() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(new ArrayList<>());
        Set<PyBoolObj> vals = node.genExVals();
        assertTrue(vals.isEmpty());
    }

    @Test
    void testIntExDomainEmpty() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(new ArrayList<>());
        Set<PyIntObj> vals = node.genExVals();
        assertTrue(vals.isEmpty());
    }

    @Test
    void testFloatExDomainEmpty() {
        PyFloatNode node = new PyFloatNode();
        node.setExDomain(new ArrayList<>());
        Set<PyFloatObj> vals = node.genExVals();
        assertTrue(vals.isEmpty());
    }
}

package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.*;

/**
 * A class that selects a minimal (concise) set of test cases that covers all
 * buggy implementations, using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Uses a greedy set cover algorithm to find a minimal set of test cases
     * from the given TestResults that collectively catch all buggy
     * implementations (files in the wrong set).
     *
     * Does not mutate the input TestResults object or any of its fields.
     *
     * @param results the test results to compute the set cover for
     * @return a set of TestCase objects forming the concise covering set
     */
    public static Set<TestCase> setCover(TestResults results) {
        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<Integer> wrongSet = results.getWrongSet();

        // Working copy of uncovered files
        Set<Integer> uncovered = new HashSet<>(wrongSet);

        // Working copies of coverage sets
        List<Set<Integer>> coverageCopies = new ArrayList<>();
        for (Set<Integer> fileSet : caseToFiles) {
            coverageCopies.add(new HashSet<>(fileSet));
        }

        Set<TestCase> result = new HashSet<>();

        while (!uncovered.isEmpty()) {
            // Find the test case covering the most uncovered files
            int bestIdx = -1;
            int bestCount = 0;

            for (int i = 0; i < coverageCopies.size(); i++) {
                int count = 0;
                for (Integer file : coverageCopies.get(i)) {
                    if (uncovered.contains(file)) {
                        count++;
                    }
                }
                if (count > bestCount) {
                    bestCount = count;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1) {
                break;
            }

            // Add the best test case to the result
            result.add(results.getTestCase(bestIdx));

            // Remove newly covered files from uncovered
            uncovered.removeAll(coverageCopies.get(bestIdx));
        }

        return result;
    }
}

package main.rice.node;

import main.rice.obj.PyFloatObj;
import java.util.*;

/**
 * A node for generating PyFloatObj values from a domain of doubles.
 */
public class PyFloatNode extends APyNode<PyFloatObj, Double> {

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyFloatObj> genExVals() {
        Set<PyFloatObj> result = new HashSet<>();
        for (Double val : this.exDomain) {
            result.add(new PyFloatObj(val));
        }
        return result;
    }

    @Override
    public PyFloatObj genRandVal() {
        Random rand = new Random();
        int idx = rand.nextInt(this.ranDomain.size());
        return new PyFloatObj(this.ranDomain.get(idx));
    }
}

