package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class whose subclasses represent nodes in a tree structure used
 * for generating test inputs. Each node generates PyObj values from a domain.
 *
 * @param <ObjType>    the type of PyObj this node generates
 * @param <DomainType> the Java type used to represent domain values
 */
public abstract class APyNode<ObjType extends APyObj, DomainType> {

    /**
     * The exhaustive domain: a list of values from which all exhaustive test
     * inputs are generated.
     */
    protected List<DomainType> exDomain;

    /**
     * The random domain: a list of values from which random test inputs are
     * generated.
     */
    protected List<DomainType> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain
     */
    public List<DomainType> getExDomain() {
        return this.exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<DomainType> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain to set
     */
    public void setExDomain(List<DomainType> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain to set
     */
    public void setRanDomain(List<DomainType> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the left child of this node, or null if this is a leaf node.
     *
     * @return the left child, or null
     */
    public abstract APyNode<?, ?> getLeftChild();

    /**
     * Returns the right child of this node, or null if this is a leaf node.
     *
     * @return the right child, or null
     */
    public abstract APyNode<?, ?> getRightChild();

    /**
     * Generates all values in the exhaustive domain, returning them as a set
     * of PyObj objects.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ObjType> genExVals();

    /**
     * Generates a single random value from the random domain.
     *
     * @return a random PyObj from the random domain
     */
    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;
import java.util.*;

/**
 * A node for generating PyBoolObj values. The domain consists of integers
 * where 0 represents false and 1 (or any non-zero) represents true.
 */
public class PyBoolNode extends APyNode<PyBoolObj, Integer> {

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyBoolObj(val != 0));
        }
        return result;
    }

    @Override
    public PyBoolObj genRandVal() {
        Random rand = new Random();
        int idx = rand.nextInt(this.ranDomain.size());
        return new PyBoolObj(this.ranDomain.get(idx) != 0);
    }
}

